from datetime import datetime
from typing import List, Dict
import re

DATE_FORMATS = ['%Y-%m-%d', '%m/%d/%Y', '%d-%m-%Y', '%Y/%m/%d']
CURRENCY_RATES = {'EUR': 1.1, 'GBP': 1.27, 'JPY': 0.0067}


def normalize_dates(records: List[Dict]) -> List[Dict]:
    for record in records:
        if 'date' in record and isinstance(record['date'], str):
            d = record['date']
            for fmt in DATE_FORMATS:
                try:
                    record['date'] = datetime.strptime(d, fmt).strftime('%Y-%m-%d')
                    break
                except ValueError:
                    continue
    return records


def clean_strings(records: List[Dict]) -> List[Dict]:
    for record in records:
        for key, value in record.items():
            if isinstance(value, str) and key != 'date':
                value = value.strip()
                value = re.sub(r'\s+', ' ', value)
                value = value.title() if key == 'name' else value
                record[key] = value
    return records


def convert_currencies(records: List[Dict], target: str = 'USD') -> List[Dict]:
    for record in records:
        if 'amount' in record and 'currency' in record:
            curr = record['currency']
            if curr != target and curr in CURRENCY_RATES:
                record['amount'] = round(record['amount'] * CURRENCY_RATES[curr], 2)
                record['currency'] = target
    return records


def deduplicate(records: List[Dict]) -> List[Dict]:
    seen = set()
    unique = []
    for record in records:
        key = (record.get('name', ''), record.get('date', ''))
        if key not in seen:
            seen.add(key)
            unique.append(record)
    return unique


def transform(records: List[Dict]) -> List[Dict]:
    records = normalize_dates(records)
    records = clean_strings(records)
    records = convert_currencies(records)
    records = deduplicate(records)
    return records
